# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 1000;
    
    public int baseDamage = 10;
    public int damageMultiplier = 1;
    
    public Dictionary<string, int> upgrades = new Dictionary<string, int>();
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }
    
    public bool CanAfford(int price)
    {
        return currency >= price;
    }
    
    public void PurchaseItem(string item, int price)
    {
        if (CanAfford(price))
        {
            currency -= price;
            ApplyUpgrade(item);
        }
    }
    
    private void ApplyUpgrade(string upgradeType)
    {
        if (upgrades.ContainsKey(upgradeType))
        {
            upgrades[upgradeType]++;
        }
        else
        {
            upgrades.Add(upgradeType, 1);
        }
        
        switch (upgradeType)
        {
            case "health":
                maxHealth += 20;
                health = maxHealth;
                break;
            case "damage":
                damageMultiplier += 1;
                break;
            case "currency":
                currency += 100;
                break;
        }
    }
    
    public int CalculateDamage()
    {
        return baseDamage * damageMultiplier;
    }
    
    public int CalculateUpgradePrice(string upgradeType, int level)
    {
        switch (upgradeType)
        {
            case "health":
                return 100 + (level * 50);
            case "damage":
                return 150 + (level * 75);
            case "currency":
                return 200 + (level * 100);
            default:
                return 100;
        }
    }
}